'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import type { Garden, Card, CardType } from '@/lib/api/types'

const CARD_TYPE_LABEL: Record<CardType, string> = {
  1: 'Text',
  2: 'Image',
  3: 'Video',
  4: 'Question',
}

interface GardenCardEditorProps {
  garden: Garden
}

export function GardenCardEditor({ garden }: GardenCardEditorProps) {
  const router = useRouter()
  const [cards, setCards] = useState<Card[]>(
    [...(garden.cards ?? [])].sort((a, b) => a.position - b.position)
  )
  const [editingId, setEditingId] = useState<number | null>(null)
  const [editContent, setEditContent] = useState('')
  const [saving, setSaving] = useState(false)
  const [approving, setApproving] = useState(false)
  const [error, setError] = useState<string | null>(null)

  async function saveCard(card: Card) {
    setSaving(true)
    setError(null)
    try {
      const res = await fetch(`/api/garden/${garden.id}/card/${card.id}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text: editContent }),
      })
      if (!res.ok) throw new Error('Failed to save card')
      setCards((prev) =>
        prev.map((c) => (c.id === card.id ? { ...c, content: editContent } : c))
      )
      setEditingId(null)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Save failed')
    } finally {
      setSaving(false)
    }
  }

  async function approveGarden() {
    setApproving(true)
    setError(null)
    try {
      const res = await fetch(`/api/garden/${garden.id}/approve`, { method: 'POST' })
      if (!res.ok) throw new Error('Failed to approve Garden')
      router.push('/garden')
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Approval failed')
      setApproving(false)
    }
  }

  return (
    <div>
      {error && (
        <div className="mb-4 text-sm text-red-600 bg-red-50 border border-red-200 rounded-lg px-3 py-2">
          {error}
        </div>
      )}

      {/* Cards */}
      <div className="space-y-3 mb-6">
        {cards.length === 0 && (
          <div className="bg-white rounded-xl border border-dashed border-stone-300 px-8 py-12 text-center">
            <p className="text-stone-400 text-sm">No cards yet for this Garden.</p>
          </div>
        )}

        {cards.map((card, index) => (
          <div
            key={card.id}
            className="bg-white border border-stone-200 rounded-xl overflow-hidden"
          >
            {/* Card header */}
            <div className="flex items-center justify-between px-5 py-3 bg-stone-50 border-b border-stone-100">
              <div className="flex items-center gap-2">
                <span className="text-xs font-medium text-stone-400">Card {index + 1}</span>
                <span className="text-xs font-medium bg-stone-200 text-stone-600 px-2 py-0.5 rounded-full">
                  {CARD_TYPE_LABEL[card.card_type]}
                </span>
              </div>
              {editingId !== card.id && (
                <button
                  onClick={() => {
                    setEditingId(card.id)
                    setEditContent(card.content)
                  }}
                  className="text-xs text-emerald-700 font-medium hover:underline"
                >
                  Edit
                </button>
              )}
            </div>

            {/* Card body */}
            <div className="px-5 py-4">
              {editingId === card.id ? (
                <div className="space-y-3">
                  <textarea
                    value={editContent}
                    onChange={(e) => setEditContent(e.target.value)}
                    rows={4}
                    className="w-full rounded-lg border border-stone-300 px-3 py-2 text-sm text-stone-900 focus:border-emerald-500 focus:outline-none focus:ring-1 focus:ring-emerald-500 resize-y"
                  />
                  <div className="flex gap-2">
                    <button
                      onClick={() => saveCard(card)}
                      disabled={saving}
                      className="text-sm font-medium bg-emerald-700 text-white px-3 py-1.5 rounded-lg hover:bg-emerald-800 disabled:opacity-50 transition-colors"
                    >
                      {saving ? 'Saving…' : 'Save'}
                    </button>
                    <button
                      onClick={() => setEditingId(null)}
                      className="text-sm font-medium text-stone-500 px-3 py-1.5 rounded-lg hover:bg-stone-100 transition-colors"
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              ) : (
                <p className="text-sm text-stone-700 whitespace-pre-wrap leading-relaxed">
                  {card.content || <span className="italic text-stone-400">No content</span>}
                </p>
              )}
            </div>
          </div>
        ))}
      </div>

      {/* Approve button */}
      {garden.status !== 'live' && (
        <div className="flex items-center justify-between bg-white border border-stone-200 rounded-xl px-5 py-4">
          <div>
            <p className="text-sm font-semibold text-stone-800">Ready to publish?</p>
            <p className="text-xs text-stone-400 mt-0.5">
              Approving will schedule this Garden to go live as planned.
            </p>
          </div>
          <button
            onClick={approveGarden}
            disabled={approving}
            className="rounded-lg bg-emerald-700 px-4 py-2 text-sm font-semibold text-white hover:bg-emerald-800 disabled:opacity-50 transition-colors"
          >
            {approving ? 'Approving…' : 'Approve Garden'}
          </button>
        </div>
      )}
    </div>
  )
}
